	private static IRI iri(ValueFactory vf, String local) {
		return vf.createIRI(EX, local);
	}

	private static Value randomValue(ValueFactory vf, Random random, Resource[] subjects) {
		switch (random.nextInt(10)) {
		case 0:
			return vf.createLiteral(random.nextInt(200) - 100);
		case 1:
			return vf.createLiteral((double) (random.nextInt(2000) - 1000) / 8);
		case 2:
			return vf.createLiteral(String.valueOf(random.nextInt(2000) - 1000), XSD.INTEGER);
		case 3:
			return vf.createLiteral(String.valueOf((random.nextInt(2000) - 1000) / 4.0), XSD.DECIMAL);
		case 4:
			return vf.createLiteral("text" + random.nextInt(30));
		case 5:
			return vf.createLiteral("wort" + random.nextInt(30), "de");
		case 6:
			return vf.createLiteral("2026-0" + (1 + random.nextInt(9)) + "-1" + random.nextInt(10), XSD.DATE);
		case 7:
			return vf.createLiteral(
					"2026-06-2" + random.nextInt(10) + "T1" + random.nextInt(10) + ":30:00", XSD.DATETIME);
		default:
			return subjects[random.nextInt(subjects.length)];
		}
	}

	private record Statement4(Resource s, IRI p, Value o, Resource c) {
	}

	@AfterEach
	public void tearDown() {
		lmdb.shutDown();
	}

	private List<String> evaluate(String query) {
		try (SailRepositoryConnection conn = lmdb.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			List<String> canonical = new ArrayList<>(rows.size());
			for (BindingSet bs : rows) {
				TreeMap<String, String> sorted = new TreeMap<>();
				for (Binding binding : bs) {
					sorted.put(binding.getName(), binding.getValue().toString());
				}
				canonical.add(sorted.toString());
			}
			return canonical;
		}
	}

	private void assertSameResults(String query) {
		List<String> actual;
		try {
			actual = evaluate(query);
		} catch (RuntimeException e) {
			throw new AssertionError("native evaluation failed for query (seed " + SEED + "):\n" + query, e);
		}
		String previous = System.getProperty(NATIVE_FLAG);
		List<String> expected;
		try {
			System.setProperty(NATIVE_FLAG, "false");
			expected = evaluate(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
		assertThat(actual)
				.as("native vs generic evaluation for query (seed %d):%n%s", SEED, query)
				.containsExactlyInAnyOrderElementsOf(expected);
	}

	private String pattern(Random random, String[] vars) {
		return pattern(random, vars, null);
	}

	/**
	 * When {@code anchor} is given, the subject is that variable, keeping multi-pattern groups connected — fully
	 * disconnected patterns build cross products whose result sets explode combinatorially.
	 */
	private String pattern(Random random, String[] vars, String anchor) {
		String s = anchor != null ? anchor
				: random.nextInt(4) == 0 ? "<" + EX + "s" + random.nextInt(16) + ">"
						: vars[random.nextInt(vars.length)];
		String p = random.nextInt(5) == 0 ? "?p" : "<" + EX + "p" + (1 + random.nextInt(5)) + ">";
		String o;
		switch (random.nextInt(6)) {
		case 0:
			o = "<" + EX + "s" + random.nextInt(16) + ">";
			break;
		case 1:
			o = String.valueOf(random.nextInt(200) - 100);
			break;
		default:
			o = vars[random.nextInt(vars.length)];
		}
		return s + " " + p + " " + o + " . ";
	}

	@Test
	public void randomBasicGraphPatterns() {
		Random random = new Random(SEED + 1);
		String[] vars = { "?a", "?b", "?c", "?d" };
		for (int i = 0; i < 120; i++) {
			StringBuilder where = new StringBuilder();
			int patterns = 1 + random.nextInt(4);
			for (int j = 0; j < patterns; j++) {
				where.append(pattern(random, vars, j == 0 ? null : vars[random.nextInt(2)]));
			}
			String distinct = random.nextBoolean() ? "DISTINCT " : "";
			assertSameResults("SELECT " + distinct + "* WHERE { " + where + "}");
		}
	}

	@Test
	public void randomOptionalUnionMinusValues() {
		Random random = new Random(SEED + 2);
		String[] vars = { "?a", "?b", "?c" };
		for (int i = 0; i < 100; i++) {
			StringBuilder where = new StringBuilder();
			where.append(pattern(random, vars));
			switch (random.nextInt(4)) {
			case 0:
				where.append("OPTIONAL { ").append(pattern(random, vars)).append("} ");
				break;
			case 1:
				where.append("{ ")
						.append(pattern(random, vars))
						.append("} UNION { ")
						.append(pattern(random, vars))
						.append("} ");
				break;
			case 2:
				where.append("MINUS { ").append(pattern(random, vars)).append("} ");
				break;
			default:
				where.append("VALUES ?a { <")
						.append(EX)
						.append("s")
						.append(random.nextInt(20))
						.append("> <")
						.append(EX)
						.append("s")
						.append(random.nextInt(20))
						.append("> } ");
			}
			if (random.nextInt(3) == 0) {
				where.append("FILTER(bound(?b)) ");
			} else if (random.nextInt(3) == 0) {
				where.append("FILTER(?a != ?b) ");
			}
			String distinct = random.nextBoolean() ? "DISTINCT " : "";
			assertSameResults("SELECT " + distinct + "* WHERE { " + where + "}");
		}
	}

	@Test
	public void randomAggregates() {
		Random random = new Random(SEED + 3);
		String[] vars = { "?a", "?b", "?c" };
		String[] aggregates = { "COUNT(?b)", "COUNT(DISTINCT ?b)", "COUNT(*)", "SUM(?b)", "MIN(?b)", "MAX(?b)",
				"AVG(?b)" };
		for (int i = 0; i < 100; i++) {
			StringBuilder where = new StringBuilder();
			int patterns = 1 + random.nextInt(3);
			for (int j = 0; j < patterns; j++) {
				where.append(pattern(random, vars));
			}
			String agg = aggregates[random.nextInt(aggregates.length)];
			boolean grouped = random.nextBoolean();
			String query;
			if (grouped) {
				query = "SELECT ?a (" + agg + " AS ?agg) WHERE { " + where + "} GROUP BY ?a";
				if (random.nextInt(3) == 0) {
					query += " HAVING(COUNT(*) > 1)";
				}
			} else {
				query = "SELECT (" + agg + " AS ?agg) WHERE { " + where + "}";
			}
			assertSameResults(query);
		}
	}

	@Test
	public void propertyPaths() {
		String edge = "<" + EX + "edge>";
		String[] starts = { "<" + EX + "s0>", "<" + EX + "s8>", "<" + EX + "s11>", "<" + EX + "s15>", "?x" };
		String[] ends = { "<" + EX + "s7>", "<" + EX + "s10>", "<" + EX + "s14>", "<" + EX + "s15>", "?y" };
		String[] ops = { "+", "*" };
		for (String start : starts) {
			for (String end : ends) {
				if (start.equals("?x") && end.equals("?y")) {
					continue; // covered below with DISTINCT to keep multiplicity comparable
				}
				for (String op : ops) {
					assertSameResults("SELECT * WHERE { " + start + " " + edge + op + " " + end + " . }");
				}
			}
		}
		assertSameResults("SELECT DISTINCT ?x ?y WHERE { ?x " + edge + "+ ?y . }");
		assertSameResults("SELECT DISTINCT ?x ?y WHERE { ?x " + edge + "* ?y . }");
		// path feeding a join and an aggregate
		assertSameResults("SELECT DISTINCT ?y ?t WHERE { <" + EX + "s0> " + edge + "+ ?y . ?y a ?t . }");
		assertSameResults(
				"SELECT (COUNT(DISTINCT ?y) AS ?c) WHERE { <" + EX + "s0> " + edge + "* ?y . }");
	}

	@Test
	public void mixedShapesWithContextsAndFilters() {
		String[] queries = {
				"SELECT ?s (COUNT(*) AS ?c) WHERE { GRAPH <" + EX + "g1> { ?s ?p ?o } } GROUP BY ?s",
				"SELECT * WHERE { GRAPH ?g { ?s <" + EX + "p1> ?o } }",
				"SELECT DISTINCT ?s WHERE { ?s ?p ?o . FILTER(isLiteral(?o)) }",
				"SELECT ?s ?o WHERE { ?s <" + EX + "p2> ?o . FILTER(?o IN (1, 2, 3, \"text1\")) }",
				"SELECT ?s WHERE { ?s a <" + EX + "T1> . FILTER NOT EXISTS { ?s <" + EX + "p1> ?z } }",
				"SELECT ?s (MIN(?d) AS ?min) (MAX(?d) AS ?max) WHERE { ?s <" + EX + "p3> ?d } GROUP BY ?s",
				"SELECT (SUM(?v) AS ?sum) WHERE { ?s <" + EX + "p4> ?v }",
				"SELECT ?s WHERE { ?s a ?t . OPTIONAL { ?s <" + EX + "p1> ?v } FILTER(!bound(?v)) }",
				"SELECT (COUNT(*) AS ?c) WHERE { ?s ?p ?o }",
				"SELECT (COUNT(*) AS ?cnt) WHERE { ?a <" + EX + "edge> ?b . ?b <" + EX + "edge> ?c . }",
		};
		for (String query : queries) {
			assertSameResults(query);
		}
	}

	@Test
	public void nativeExpressionHotCatalogMatchesGenericEvaluator() {
		String[] queries = {
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(?o + 2 >= 10) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(?o / 2 < 25) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(CONTAINS(LCASE(STR(?o)), \"text\")) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(STRSTARTS(UCASE(STR(?o)), \"TEXT\")) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(STRENDS(STR(?o), \"1\")) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(REGEX(STR(?o), \"^(text|wort)[0-9]+$\", \"i\")) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(STRLEN(STR(?o)) > 4) }",
				"PREFIX xsd: <http://www.w3.org/2001/XMLSchema#> "
						+ "SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(DATATYPE(?o) = xsd:integer) }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(LANG(?o) = \"de\") }",
				"SELECT ?s ?o WHERE { ?s ?p ?o . FILTER(!(?missing = 1)) }",
		};
		for (String query : queries) {
			assertSameResults(query);
		}
	}
